def parser(log: str) -> dict[str, str]:
    import re

    results = {}

    subtest_re = re.compile(r'^(\s*)# Subtest:\s*(.*)$')
    ok_re = re.compile(r'^(\s*)(ok|not ok)\s+\d+(?:\s*-\s*([^#]*?))?(?:\s+#\s*(.*))?$')
    plan_re = re.compile(r'^\s*1\.\.\d+')
    version_re = re.compile(r'^\s*TAP version')
    bailout_re = re.compile(r'^\s*Bail out!')

    stack = []  # [{'indent': int, 'name': str}]
    pending_name_by_indent = {}

    def norm_indent(s: str) -> int:
        return len(s.replace('\t', '    '))

    def add_result(name: str, status: str):
        base = name.strip() if name else "<unnamed>"
        if base in results:
            i = 2
            while f"{base} (#{i})" in results:
                i += 1
            base = f"{base} (#{i})"
        results[base] = status

    for raw in log.splitlines():
        line = raw.rstrip("\n")
        if not line.strip():
            continue

        if version_re.match(line) or plan_re.match(line) or bailout_re.match(line):
            continue

        m = subtest_re.match(line)
        if m:
            indent = norm_indent(m.group(1))
            name = m.group(2).strip()
            if not name:
                name = pending_name_by_indent.get(indent, "") or "<anonymous subtest>"
            # pop to correct nesting level
            while stack and indent <= stack[-1]["indent"]:
                stack.pop()
            stack.append({"indent": indent, "name": name})
            pending_name_by_indent.pop(indent, None)
            continue

        m = ok_re.match(line)
        if m:
            indent = norm_indent(m.group(1))
            ok_status = m.group(2)
            name = (m.group(3) or "").strip() or "<unnamed>"
            comment = (m.group(4) or "").strip()
            directive = comment.split()[0].upper() if comment else ""

            if directive in {"SKIP", "TODO"}:
                status = "skip"
            else:
                status = "pass" if ok_status == "ok" else "fail"

            # Determine if this is a subtest summary line to pop stack
            is_summary = False
            if stack and indent <= stack[-1]["indent"] and name == stack[-1]["name"]:
                is_summary = True

            if is_summary:
                context = [s["name"] for s in stack[:-1] if s["name"]]
                full_name = " / ".join(context + [name]) if context else name
                add_result(full_name, status)
                stack.pop()
            else:
                # Assertion line
                context = [s["name"] for s in stack if s["name"]]
                # avoid repeating the same name twice at the end
                if context and context[-1] == name:
                    full_name = " / ".join(context)
                else:
                    full_name = " / ".join(context + [name]) if context else name
                add_result(full_name, status)
            continue

        # capture pending name for anonymous subtests
        stripped = line.strip()
        if stripped and not stripped.startswith("#"):
            indent = len(line) - len(line.lstrip(' \t'))
            indent = norm_indent(line[:indent])
            pending_name_by_indent[indent] = stripped

    return results
